# Let's write a small C# script to check if ResponseError implements IJsonModel
import subprocess
script = '''
using System;
using System.Reflection;
using Azure;

var t = typeof(ResponseError);
foreach (var iface in t.GetInterfaces())
{
    Console.WriteLine(iface.FullName ?? iface.Name);
}
Console.WriteLine("---Methods---");
foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance | BindingFlags.Static))
{
    if (m.Name.Contains("Deserialize") || m.Name.Contains("Write") || m.Name.Contains("Create") || m.Name.Contains("Json"))
        Console.WriteLine($"{m.DeclaringType?.Name}.{m.Name}");
}
'''

# Write a temp project
import os, tempfile
tmpdir = tempfile.mkdtemp()
with open(os.path.join(tmpdir, 'Program.cs'), 'w') as f:
    f.write(script)
with open(os.path.join(tmpdir, 'test.csproj'), 'w') as f:
    f.write('''<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup><OutputType>Exe</OutputType><TargetFramework>net9.0</TargetFramework></PropertyGroup>
  <ItemGroup><PackageReference Include="Azure.Core" Version="1.46.1" /></ItemGroup>
</Project>''')

result = subprocess.run(['dotnet', 'run', '--project', os.path.join(tmpdir, 'test.csproj')], 
                       capture_output=True, text=True, timeout=60)
print(result.stdout)
if result.stderr:
    print("STDERR:", result.stderr[:500])

# Cleanup
import shutil
shutil.rmtree(tmpdir)
PYEOF

