    Console.WriteLine($"  Property: {p.PropertyType.Name} {p.Name}");
foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
{
    var parms = string.Join(", ", Array.ConvertAll(c.GetParameters(), p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"  Constructor({(c.IsPublic?"public":"non-public")}): ({parms})");
}
// Check for JsonConverter attribute
foreach (var attr in t.GetCustomAttributes(true))
    Console.WriteLine($"  Attribute: {attr.GetType().FullName}");
'''

tmpdir = tempfile.mkdtemp()
with open(os.path.join(tmpdir, 'Program.cs'), 'w') as f:
    f.write(script)
with open(os.path.join(tmpdir, 'test.csproj'), 'w') as f:
    f.write('''<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup><OutputType>Exe</OutputType><TargetFramework>net9.0</TargetFramework></PropertyGroup>
  <ItemGroup><PackageReference Include="Azure.Core" Version="1.46.1" /></ItemGroup>
